1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const COMPONENT_BASE = 25;
25	const BLOCK_SIZE = 3;
26	const BLOCK_BASE = 60;
27	
28	const FIRST_INSURANCE_MULTIPLIER = 1.1;
29	const PROCESSING_FEE = 5;
30	const ROUNDING_PRECISION = 6;
31	
32	const componentGroupBase = (count: number): number =>
33	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
34	
35	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
36	
37	const mainItemBase = (items: Item[]): number =>
38	  items
39	    .filter((item) => !isComponent(item))
40	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
41	
42	const componentBase = (items: Item[]): number => {
43	  const counts: Record<string, number> = {};
44	  for (const item of items.filter(isComponent)) {
45	    counts[item.type] = (counts[item.type] ?? 0) + 1;
46	  }
47	  return Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
48	};
49	
50	const roundUpToWhole = (amount: number): number =>
51	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
52	
53	const quotePremium = (items: Item[]): number => {
54	  const base = mainItemBase(items) + componentBase(items);
55	  return roundUpToWhole(base * FIRST_INSURANCE_MULTIPLIER + PROCESSING_FEE);
56	};
57	
58	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
59	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
60	  return { results };
61	};
